import{_ as e,o as a,c as n,a7 as r}from"./chunks/framework.C5fSpjcB.js";const c=JSON.parse('{"title":"Engravings","description":"","frontmatter":{},"headers":[],"relativePath":"en/engravings/index.md","filePath":"en/engravings/index.md","lastUpdated":1775394001000}'),i={name:"en/engravings/index.md"};function s(o,t,d,l,g,h){return a(),n("div",null,[...t[0]||(t[0]=[r('<h1 id="engravings" tabindex="-1">Engravings <a class="header-anchor" href="#engravings" aria-label="Permalink to &quot;Engravings&quot;">​</a></h1><p><strong>Engravings</strong> (刻印) are enhancement items in Morimens that provide additional stat bonuses and special effects to your Awakeners. They serve as a supplementary gear layer on top of Wheels of Destiny and Covenants.</p><h2 id="overview" tabindex="-1">Overview <a class="header-anchor" href="#overview" aria-label="Permalink to &quot;Overview&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Aspect</th><th>Detail</th></tr></thead><tbody><tr><td>Type</td><td>Enhancement items</td></tr><tr><td>Acquisition</td><td>Stages, events, Investigation</td></tr><tr><td>Equip Limit</td><td>Multiple slots per Awakener</td></tr><tr><td>Purpose</td><td>Supplementary stats and effects</td></tr></tbody></table><h2 id="how-engravings-work" tabindex="-1">How Engravings Work <a class="header-anchor" href="#how-engravings-work" aria-label="Permalink to &quot;How Engravings Work&quot;">​</a></h2><ul><li>Engravings are equipped in dedicated slots on each Awakener.</li><li>They provide <strong>flat stat bonuses</strong> (ATK, DEF, CON) and may include <strong>sub-stats</strong> or <strong>special effects</strong>.</li><li>Engravings can be swapped freely between Awakeners.</li></ul><h2 id="engraving-stats" tabindex="-1">Engraving Stats <a class="header-anchor" href="#engraving-stats" aria-label="Permalink to &quot;Engraving Stats&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Stat Type</th><th>Description</th></tr></thead><tbody><tr><td>Main Stat</td><td>Primary stat bonus (fixed by Engraving type)</td></tr><tr><td>Sub-Stats</td><td>Secondary random stats rolled on the Engraving</td></tr><tr><td>Special Effect</td><td>Some Engravings grant unique passive effects</td></tr></tbody></table><h2 id="obtaining-engravings" tabindex="-1">Obtaining Engravings <a class="header-anchor" href="#obtaining-engravings" aria-label="Permalink to &quot;Obtaining Engravings&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Source</th><th>Notes</th></tr></thead><tbody><tr><td>Stage Drops</td><td>Farm from resource and challenge stages</td></tr><tr><td><a href="./../modes/investigation.html">Investigation</a></td><td>Random drops during Investigation runs</td></tr><tr><td>Event Rewards</td><td>Limited-time event shops</td></tr><tr><td><a href="./../modes/smelting.html">Smelting Room</a></td><td>Craft specific Engravings</td></tr></tbody></table><h2 id="engraving-priority" tabindex="-1">Engraving Priority <a class="header-anchor" href="#engraving-priority" aria-label="Permalink to &quot;Engraving Priority&quot;">​</a></h2><ol><li><strong>Main DPS</strong> -- Equip your strongest offensive Engravings on your primary damage dealer.</li><li><strong>Sub-DPS</strong> -- Use moderate Engravings that boost damage or utility.</li><li><strong>Support/Tank</strong> -- Defensive or HP-focused Engravings for survivability.</li></ol><div class="tip custom-block"><p class="custom-block-title">TIP</p><p>Do not overlook sub-stats on Engravings. A lower-rarity Engraving with perfect sub-stats can outperform a higher-rarity one with bad rolls.</p></div><h2 id="see-also" tabindex="-1">See Also <a class="header-anchor" href="#see-also" aria-label="Permalink to &quot;See Also&quot;">​</a></h2><ul><li><a href="./list.html">Engravings List</a></li><li><a href="./../wheels/">Wheels of Destiny</a></li><li><a href="./../covenants/">Covenants</a></li></ul>',15)])])}const u=e(i,[["render",s]]);export{c as __pageData,u as default};
